Code.Terraform:
```hcl
# Terraform: すべてのアクティブな Inspector 検出結果を抑制
resource "aws_inspector2_filter" "<example_resource_name>" {
  name   = "<example_resource_name>"
  action = "SUPPRESS"  # 重要: 一致する検出結果をアクティブではなく抑制済みに変換します

  filter_criteria {
    finding_status {
      comparison = "EQUALS"
      value      = "ACTIVE"  # 重要: すべてのアクティブな検出結果を対象とします
    }
  }
}
```
